import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';

function Dashboard() {
 const { currentUser, logout, loading } = useAuth();
const [activeTab, setActiveTab] = useState('overview');

useEffect(() => {
  if (!loading && !currentUser) {
    window.location.href = '/login';
  }
}, [currentUser, loading]);

if (loading) return (
  <div style={{
    minHeight: '100vh',
    background: '#080808',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    color: '#22c55e',
    fontSize: '24px'
  }}>
    🦉 Loading...
  </div>
);

if (!currentUser) return null;

  const navItems = [
    { id: 'overview',  icon: '🏠', label: 'Overview'        },
    { id: 'dsa',       icon: '📊', label: 'DSA Tracker'     },
    { id: 'github',    icon: '🐙', label: 'GitHub'          },
    { id: 'ai',        icon: '🤖', label: 'AI Mentor'       },
    { id: 'portfolio', icon: '🌐', label: 'Portfolio'       },
  ];

  return (
    <div style={s.page}>

      {/* ── Sidebar ── */}
      <div style={s.sidebar}>
        <div style={s.sidebarLogo}>
          <span style={s.owl}>🦉</span>
          <span style={s.logoText}>DevNest</span>
        </div>

        <nav style={s.nav}>
          {navItems.map(item => (
            <div
              key={item.id}
              style={{
                ...s.navItem,
                ...(activeTab === item.id ? s.navItemActive : {})
              }}
              onClick={() => setActiveTab(item.id)}
            >
              <span style={s.navIcon}>{item.icon}</span>
              <span style={s.navLabel}>{item.label}</span>
              {activeTab === item.id && <div style={s.navActiveDot}></div>}
            </div>
          ))}
        </nav>

        <div style={s.sidebarBottom}>
          <div style={s.userInfo}>
            <div style={s.avatar}>
              {currentUser.name?.charAt(0).toUpperCase()}
            </div>
            <div>
              <div style={s.userName}>{currentUser.name}</div>
              <div style={s.userEmail}>{currentUser.email}</div>
            </div>
          </div>
          <button onClick={logout} style={s.logoutBtn}>
            Logout →
          </button>
        </div>
      </div>

      {/* ── Main Content ── */}
      <div style={s.main}>

        {/* Top bar */}
        <div style={s.topBar}>
          <div>
            <h1 style={s.pageTitle}>
              {navItems.find(n => n.id === activeTab)?.icon}{' '}
              {navItems.find(n => n.id === activeTab)?.label}
            </h1>
            <p style={s.pageSubtitle}>
              {new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
            </p>
          </div>
          <div style={s.welcomeBadge}>
            Welcome back, {currentUser.name?.split(' ')[0]} 👋
          </div>
        </div>

        {/* Overview Tab */}
        {activeTab === 'overview' && (
          <div>
            {/* Stats Grid */}
            <div style={s.statsGrid}>
              {[
                { icon: '📊', label: 'Problems Solved',    value: '0',    sub: 'of 25 total',      color: '#22c55e' },
                { icon: '🐙', label: 'GitHub Repos',       value: '--',   sub: 'Connect GitHub',   color: '#3b82f6' },
                { icon: '🔥', label: 'Day Streak',         value: '1',    sub: 'Keep it up!',      color: '#f59e0b' },
                { icon: '🎯', label: 'Readiness Score',    value: '--',   sub: 'Complete profile', color: '#a855f7' },
              ].map(stat => (
                <div key={stat.label} style={s.statCard}>
                  <div style={s.statTop}>
                    <span style={s.statIcon}>{stat.icon}</span>
                    <span style={s.statLabel}>{stat.label}</span>
                  </div>
                  <div style={{ ...s.statValue, color: stat.color }}>{stat.value}</div>
                  <div style={s.statSub}>{stat.sub}</div>
                </div>
              ))}
            </div>

            {/* Quick Actions */}
            <h2 style={s.sectionTitle}>Quick Actions</h2>
            <div style={s.actionsGrid}>
              {[
                { icon: '📊', title: 'Start DSA Practice',   desc: 'Pick up from where you left off',  tab: 'dsa',       color: '#22c55e' },
                { icon: '🐙', title: 'Connect GitHub',       desc: 'Sync your repos and activity',     tab: 'github',    color: '#3b82f6' },
                { icon: '🤖', title: 'Get AI Roadmap',       desc: 'Personalized prep plan for you',   tab: 'ai',        color: '#a855f7' },
                { icon: '🌐', title: 'View Portfolio',       desc: 'See your public profile',          tab: 'portfolio', color: '#f59e0b' },
              ].map(action => (
                <div
                  key={action.title}
                  style={s.actionCard}
                  onClick={() => setActiveTab(action.tab)}
                >
                  <div style={{ ...s.actionIconWrap, background: `${action.color}15`, border: `1px solid ${action.color}30` }}>
                    <span style={s.actionIcon}>{action.icon}</span>
                  </div>
                  <div style={s.actionTitle}>{action.title}</div>
                  <div style={s.actionDesc}>{action.desc}</div>
                  <div style={{ ...s.actionArrow, color: action.color }}>→</div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Other tabs — coming soon */}
        {activeTab !== 'overview' && (
          <div style={s.comingSoon}>
            <div style={s.comingSoonIcon}>
              {navItems.find(n => n.id === activeTab)?.icon}
            </div>
            <h2 style={s.comingSoonTitle}>
              {navItems.find(n => n.id === activeTab)?.label} — Coming Soon
            </h2>
            <p style={s.comingSoonText}>
              We're building this section. Check back soon!
            </p>
            <button
              style={s.backBtn}
              onClick={() => setActiveTab('overview')}
            >
              ← Back to Overview
            </button>
          </div>
        )}
      </div>

      <style>{`
        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-track { background: #0d0d0d; }
        ::-webkit-scrollbar-thumb { background: #2a2a2a; border-radius: 3px; }
      `}</style>
    </div>
  );
}

